// Arma un dashboard HTML muy simple a partir de las filas de la planilla.
const rows = items.map(i => i.json);
const paises = [...new Set(rows.map(r => r['País']).filter(Boolean))];
const mate = rows.filter(r => (r['Mate o café']||'').toLowerCase().includes('mate')).length;
const cafe = rows.filter(r => (r['Mate o café']||'').toLowerCase().includes('caf')).length;

const html = `
<html><head><meta http-equiv="refresh" content="10"></head>
<body style="font-family:sans-serif;background:#F8F2E8;color:#260700;padding:40px;">
  <h1>Así es esta comisión</h1>
  <p><b>Respuestas recibidas:</b> ${rows.length}</p>
  <p><b>Países:</b> ${paises.join(', ') || '—'}</p>
  <p><b>Mate vs. café:</b> ${mate} mate · ${cafe} café</p>
  <p style="opacity:.6;font-size:12px;">Se actualiza sola cada 10 segundos.</p>
</body></html>`;

return [{ json: { html } }];
